                 // If n=3, range [2..1] is empty. Inner cost is 0. Total cost is costs[0].
                 min_cost = Math.min(min_cost, costs[0]);
            }
        }


        if (min_cost >= Long.MAX_VALUE / 2) {
            return -1;
        }
        return min_cost;
    }
}
